  1	import { render, screen, fireEvent } from '@testing-library/react';
  2	import { vi, expect, describe, beforeEach, it } from 'vitest';
  3	
  4	import { SiteView } from '../src/console/interfaces/REST.interfaces';
  5	import Details from '../src/console/pages/tabs/Details/Details';
  6	
  7	const mockUseWatchedSkupperResource = vi.hoisted(() => vi.fn());
  8	
  9	vi.mock('../src/console/hooks/useSkupperWatchResource', () => ({
 10	  useWatchedSkupperResource: mockUseWatchedSkupperResource
 11	}));
 12	
 13	vi.mock('../src/console/pages/tabs/Details/Header', () => ({
 14	  default: ({ site, t }: { site: SiteView; t: (key: string) => string }) => (
 15	    <div data-testid="mock-header">
 16	      Header Component {site?.name} {t('Site settings')}
 17	    </div>
 18	  )
 19	}));
 20	
 21	describe('Details Component', () => {
 22	  const mockOnGoTo = vi.fn();
 23	
 24	  const mockSite = {
 25	    name: 'test-site',
 26	    linkAccess: 'public',
 27	    serviceAccount: 'test-account',
 28	    defaultIssuer: 'test-issuer',
 29	    ha: true,
 30	    isConfigured: true,
 31	    platform: 'kubernetes',
 32	    creationTimestamp: '2024-02-05T12:00:00Z',
 33	    conditions: [
 34	      {
 35	        type: 'Ready',
 36	        status: 'True',
 37	        reason: 'Success',
 38	        message: 'Site is ready',
 39	        lastTransitionTime: '2024-02-05T12:00:00Z'
 40	      }
 41	    ],
 42	    resourceVersion: '123'
 43	  };
 44	
 45	  beforeEach(() => {
 46	    vi.clearAllMocks();
 47	    mockUseWatchedSkupperResource.mockReturnValue({
 48	      data: [mockSite]
 49	    });
 50	  });
 51	
 52	  it('renders basic site details', () => {
 53	    render(<Details onGoTo={mockOnGoTo} />);
 54	    expect(screen.getByText(mockSite.name)).toBeInTheDocument();
 55	    expect(screen.getByText(mockSite.linkAccess)).toBeInTheDocument();
 56	    expect(screen.getByText(mockSite.platform)).toBeInTheDocument();
 57	  });
 58	
 59	  it('handles modal interactions', () => {
 60	    render(<Details onGoTo={mockOnGoTo} />);
 61	
 62	    const editButtons = screen.getByTestId('edit-link-access-button');
 63	    fireEvent.click(editButtons);
 64	
 65	    expect(screen.getByText('Edit site')).toBeInTheDocument();
 66	
 67	    fireEvent.click(screen.getByRole('button', { name: 'Cancel' }));
 68	    expect(screen.queryByText('Edit site')).not.toBeInTheDocument();
 69	  });
 70	
 71	  it('renders conditions with different states', () => {
 72	    const siteWithConditions = {
 73	      ...mockSite,
 74	      conditions: [
 75	        {
 76	          type: 'Error',
 77	          status: 'False',
 78	          reason: 'Error',
 79	          message: 'Error message',
 80	          lastTransitionTime: '2024-02-05T12:00:00Z'
 81	        },
 82	        {
 83	          type: 'Pending',
 84	          status: 'Unknown',
 85	          reason: 'Pending',
 86	          message: 'Pending message',
 87	          lastTransitionTime: '2024-02-05T12:00:00Z'
 88	        }
 89	      ]
 90	    };
 91	
 92	    mockUseWatchedSkupperResource.mockReturnValue({
 93	      data: [siteWithConditions]
 94	    });
 95	
 96	    render(<Details onGoTo={mockOnGoTo} />);
 97	    expect(screen.getAllByText('Error')[0]).toBeInTheDocument();
 98	    expect(screen.getAllByText('Pending')[0]).toBeInTheDocument();
 99	  });
100	
101	  it('renders conditions table when conditions exist', () => {
102	    render(<Details onGoTo={mockOnGoTo} />);
103	    expect(screen.getByText('Conditions')).toBeInTheDocument();
104	    expect(screen.getByText('Ready')).toBeInTheDocument();
105	  });
106	
107	  it('handles site with no conditions', () => {
108	    mockUseWatchedSkupperResource.mockReturnValue({
109	      data: [
110	        {
111	          ...mockSite,
112	          conditions: undefined
113	        }
114	      ]
115	    });
116	
117	    render(<Details onGoTo={mockOnGoTo} />);
118	    expect(screen.queryByText('Conditions')).not.toBeInTheDocument();
119	  });
120	});

