  1	import { FC, useCallback, useState } from 'react';
  2	
  3	import {
  4	  DEFAULT_ISSUER,
  5	  DEFAULT_SERVICE_ACCOUNT,
  6	  EMPTY_LINK_ACCESS,
  7	  EMPTY_VALUE_SYMBOL,
  8	  I18nNamespace
  9	} from '@config/config';
 10	import FormatDateCell from '@core/components/FormatDate';
 11	import { TooltipInfoButton } from '@core/components/HelpTooltip';
 12	import SkTable from '@core/components/SkTable';
 13	import { useWatchedSkupperResource } from '@hooks/useSkupperWatchResource';
 14	import { CrdStatusCondition, StatusSiteType } from '@interfaces/CRD_Base';
 15	import { SKColumn, SKComponentProps } from '@interfaces/SkTable.interfaces';
 16	import {
 17	  DescriptionList,
 18	  DescriptionListTerm,
 19	  DescriptionListGroup,
 20	  DescriptionListDescription,
 21	  Card,
 22	  CardHeader,
 23	  CardBody,
 24	  Title,
 25	  Button,
 26	  Modal,
 27	  ModalVariant,
 28	  Icon
 29	} from '@patternfly/react-core';
 30	import { CheckCircleIcon, ExclamationCircleIcon, PenIcon } from '@patternfly/react-icons';
 31	import { useTranslation } from 'react-i18next';
 32	
 33	import Header from './Header';
 34	import SiteForm from '../../components/forms/SiteForm';
 35	import Status from '../Links/Status';
 36	
 37	const Details: FC<{ onGoTo: (page: number) => void }> = function ({ onGoTo }) {
 38	  const { t } = useTranslation(I18nNamespace);
 39	  const { data: sites } = useWatchedSkupperResource({ kind: 'Site' });
 40	
 41	  const [isModalOpen, setIsModalOpen] = useState(false);
 42	
 43	  const [visibleModalPros, setVisibleModalProps] = useState<Record<string, boolean>>({});
 44	
 45	  const handleOpenModal = (props: Record<string, boolean>) => {
 46	    setIsModalOpen(true);
 47	    setVisibleModalProps(props);
 48	  };
 49	
 50	  const handleClose = useCallback(() => {
 51	    setIsModalOpen(false);
 52	  }, []);
 53	
 54	  const ConditionsColumns: SKColumn<CrdStatusCondition<StatusSiteType>>[] = [
 55	    {
 56	      name: t('Type'),
 57	      prop: 'type',
 58	      width: 20
 59	    },
 60	    {
 61	      name: t('Status'),
 62	      prop: 'status',
 63	      width: 20,
 64	      customCellName: 'StatusCell'
 65	    },
 66	
 67	    {
 68	      name: t('Reason'),
 69	      prop: 'reason',
 70	      customCellName: 'ReasonCell'
 71	    },
 72	    {
 73	      name: t('Message'),
 74	      prop: 'message',
 75	      customCellName: 'ValueOrEmptyCell'
 76	    },
 77	    {
 78	      name: t('Updated'),
 79	      prop: 'lastTransitionTime',
 80	      customCellName: 'FormatOCPDateCell',
 81	      modifier: 'fitContent'
 82	    }
 83	  ];
 84	
 85	  const customSiteCells = {
 86	    FormatOCPDateCell: FormatDateCell,
 87	    ValueOrEmptyCell: ({ value, data }: SKComponentProps<CrdStatusCondition<StatusSiteType>>) =>
 88	      data.reason === 'Error' ? value : EMPTY_VALUE_SYMBOL,
 89	    ReasonCell: ({ data }: SKComponentProps<CrdStatusCondition<StatusSiteType>>) =>
 90	      data.reason === 'Error' || data.reason === 'Pending' ? data.reason : EMPTY_VALUE_SYMBOL,
 91	    StatusCell: ({ data }: SKComponentProps<CrdStatusCondition<StatusSiteType>>) => {
 92	      if (data.reason === 'Error') {
 93	        return (
 94	          <Icon status="danger">
 95	            <ExclamationCircleIcon />
 96	          </Icon>
 97	        );
 98	      }
 99	
100	      if (data.reason === 'Pending') {
101	        return EMPTY_VALUE_SYMBOL;
102	      }
103	
104	      return (
105	        <Icon status="success">
106	          <CheckCircleIcon />
107	        </Icon>
108	      );
109	    }
110	  };
111	
112	  const site = sites?.[0];
113	
114	  return (
115	    <>
116	      <Card isPlain data-testid="details">
117	        <CardHeader>
118	          <Header site={site} t={t} />
119	        </CardHeader>
120	
121	        <CardBody>
122	          <DescriptionList
123	            columnModifier={{
124	              default: '2Col'
125	            }}
126	          >
127	            <DescriptionListGroup>
128	              <DescriptionListTerm>{t('Name')}</DescriptionListTerm>
129	              <DescriptionListDescription>{site?.name}</DescriptionListDescription>
130	            </DescriptionListGroup>
131	
132	            <DescriptionListGroup>
133	              <DescriptionListTerm>
134	                {t('Link access')} <TooltipInfoButton content={t('tooltipSiteLinkAccess')} />
135	              </DescriptionListTerm>
136	              <DescriptionListDescription>
137	                {site?.linkAccess || EMPTY_LINK_ACCESS}{' '}
138	                <Button
139	                  data-testid="edit-link-access-button"
140	                  variant="plain"
141	                  onClick={() => handleOpenModal({ linkAccess: true })}
142	                  icon={<PenIcon />}
143	                  isDisabled={!site?.isConfigured}
144	                />
145	              </DescriptionListDescription>
146	            </DescriptionListGroup>
147	
148	            <DescriptionListGroup>
149	              <DescriptionListTerm>{t('Service account')}</DescriptionListTerm>
150	              <DescriptionListDescription>
151	                {`${site?.serviceAccount}` || DEFAULT_SERVICE_ACCOUNT}{' '}
152	                <Button
153	                  data-testid="edit-service-account-button"
154	                  variant="plain"
155	                  onClick={() => handleOpenModal({ serviceAccount: true })}
156	                  icon={<PenIcon />}
157	                  isDisabled={!site?.isConfigured}
158	                />
159	              </DescriptionListDescription>
160	            </DescriptionListGroup>
161	
162	            <DescriptionListGroup>
163	              <DescriptionListTerm>{t('Default issuer')}</DescriptionListTerm>
164	              <DescriptionListDescription>
165	                {`${site?.defaultIssuer}` || DEFAULT_ISSUER}{' '}
166	                <Button
167	                  data-testid="edit-default-issuer-button"
168	                  variant="plain"
169	                  onClick={() => handleOpenModal({ defaultIssuer: true })}
170	                  icon={<PenIcon />}
171	                  isDisabled={!site?.isConfigured}
172	                />
173	              </DescriptionListDescription>
174	            </DescriptionListGroup>
175	
176	            <DescriptionListGroup>
177	              <DescriptionListTerm>{t('tooltipHighAvailability')}</DescriptionListTerm>
178	              <DescriptionListDescription>
179	                {`${site?.ha}`}{' '}
180	                <Button
181	                  data-testid="edit-ha-button"
182	                  variant="plain"
183	                  onClick={() => handleOpenModal({ ha: true })}
184	                  icon={<PenIcon />}
185	                  isDisabled={!site?.isConfigured}
186	                />
187	              </DescriptionListDescription>
188	            </DescriptionListGroup>
189	          </DescriptionList>
190	        </CardBody>
191	      </Card>
192	
193	      <Card isPlain>
194	        <Status site={site} t={t} onGoTo={onGoTo} />
195	      </Card>
196	      <Card isPlain>
197	        <CardHeader>
198	          <Title headingLevel="h1">{t('Details')}</Title>
199	        </CardHeader>
200	
201	        <CardBody>
202	          <DescriptionList>
203	            <DescriptionListGroup>
204	              <DescriptionListTerm>{t('Platform')}</DescriptionListTerm>
205	              <DescriptionListDescription>{`${site?.platform}` || EMPTY_VALUE_SYMBOL}</DescriptionListDescription>
206	            </DescriptionListGroup>
207	
208	            <DescriptionListGroup>
209	              <DescriptionListTerm>{t('Created at')}</DescriptionListTerm>
210	              <DescriptionListDescription>
211	                {site?.isConfigured ? <FormatDateCell value={new Date(site.creationTimestamp)} /> : EMPTY_VALUE_SYMBOL}
212	              </DescriptionListDescription>
213	            </DescriptionListGroup>
214	          </DescriptionList>
215	        </CardBody>
216	      </Card>
217	
218	      {site?.conditions && (
219	        <Card isPlain>
220	          <CardHeader>
221	            <Title headingLevel="h1">{t('Conditions')}</Title>
222	          </CardHeader>
223	
224	          <CardBody>
225	            <SkTable
226	              columns={ConditionsColumns}
227	              rows={site?.conditions}
228	              alwaysShowPagination={false}
229	              isPlain
230	              customCells={customSiteCells}
231	              variant="compact"
232	            />
233	          </CardBody>
234	        </Card>
235	      )}
236	      <Modal
237	        title={t('Edit site')}
238	        variant={ModalVariant.medium}
239	        isOpen={isModalOpen}
240	        aria-label="Form edit site"
241	        showClose={false}
242	      >
243	        <SiteForm
244	          siteName={site?.name}
245	          linkAccess={site?.linkAccess}
246	          serviceAccount={site?.serviceAccount}
247	          defaultIssuer={site?.defaultIssuer}
248	          ha={site?.ha}
249	          show={visibleModalPros}
250	          resourceVersion={site?.resourceVersion}
251	          onCancel={handleClose}
252	        />
253	      </Modal>
254	    </>
255	  );
256	};
257	
258	export default Details;

