  1	import { useState, FC, useCallback, KeyboardEvent } from 'react';
  2	
  3	import { RESTApi } from '@API/REST.api';
  4	import { DEFAULT_ISSUER, DEFAULT_SERVICE_ACCOUNT, I18nNamespace } from '@config/config';
  5	import { NamespaceManager } from '@config/db';
  6	import { TooltipInfoButton } from '@core/components/HelpTooltip';
  7	import LoadingPage from '@core/components/Loading';
  8	import { createSiteData } from '@core/utils/createCRD';
  9	import useValidatedInput from '@hooks/useValidation';
 10	import { SiteCrdParams } from '@interfaces/CRD_Site';
 11	import { HTTPError } from '@interfaces/REST.interfaces';
 12	import {
 13	  Form,
 14	  FormGroup,
 15	  TextInput,
