 35	const options = [
 36	  { value: 'route', label: 'route', disabled: false },
 37	  { value: 'loadbalancer', label: 'loadbalancer', disabled: false },
 38	  { value: 'default', label: 'default', disabled: false }
 39	];
 40	
 41	interface SiteFormProps {
 42	  siteName?: string;
 43	  linkAccess?: string;
 44	  serviceAccount?: string;
 45	  defaultIssuer?: string;
 46	  ha?: boolean;
 47	  resourceVersion?: string;
 48	  show?: { linkAccess?: boolean; name?: boolean; ha?: boolean; serviceAccount?: boolean; defaultIssuer?: boolean };
 49	  onCancel: () => void;
 50	}
 51	
 52	const SiteForm: FC<SiteFormProps> = function ({
 53	  siteName,
 54	  linkAccess: initLinkAccess,
 55	  serviceAccount: initServiceAccount,
 56	  defaultIssuer: initDefaultIssuer,
 57	  ha: initHa,
 58	  resourceVersion,
 59	  show = { linkAccess: true, name: true, ha: true, serviceAccount: true, defaultIssuer: true },
 60	  onCancel
 61	}) {
 62	  const [step, setNextStep] = useState(0);
 63	
 64	  const handleReady = () => {
 65	    if (siteName) {
 66	      onCancel?.();
 67	    } else {
 68	      setNextStep(1);
 69	    }
 70	  };
 71	
 72	  const steps = [
 73	    <FormPage
 74	      key={1}
