129	  const [serviceAccount, setServiceAccount] = useState(initServiceAccount || '');
130	  const [defaultIssuer, setDefaultIssuer] = useState(initDefaultIssuer || '');
131	  const [ha, setHa] = useState(initHa || false);
132	
133	  const [isExpanded, setIsExpanded] = useState(false);
134	  const { validated, validateInput } = useValidatedInput();
135	
136	  const handleToggle = useCallback(() => {
137	    setIsExpanded(!isExpanded);
138	  }, [isExpanded]);
