141	    setName(value);
142	  };
143	
144	  const handleChangeLinkAccess = (value: string) => {
145	    setLinkAccess(value);
146	  };
147	
148	  const handleChangeServiceAccount = useCallback((value: string) => {
149	    setServiceAccount(value);
150	  }, []);
151	
152	  const handleDefaultIssuer = useCallback((value: string) => {
153	    setDefaultIssuer(value);
154	  }, []);
155	
156	  const handleChangeHa = useCallback((value: boolean) => {
157	    setHa(value);
158	  }, []);
159	
160	  const handleSubmit = () => {
161	    const data: SiteCrdParams = createSiteData({
162	      metadata: { name, resourceVersion },
163	      spec: {
164	        linkAccess: isLinkAccessExist ? linkAccess : undefined,
165	        serviceAccount,
166	        defaultIssuer,
167	        ha
168	      }
169	    });
170	
171	    mutationCreateOrUpdate.mutate(data);
172	  };
173	
174	  const handleKeyPress = (event: KeyboardEvent) => {
175	    if (event.key === 'Enter' && !!name) {
176	      event.preventDefault(); // Prevents the default Enter key behavior
177	      handleSubmit();
178	    }
179	  };
180	
181	  const canSubmit = !!name; //&& !validated;
182	
183	  return (
184	    <Form isHorizontal onKeyDown={handleKeyPress} data-testid="site-form">
185	      {(show.name || show.ha) && (
186	        <FormGroup fieldId="name-input" isRequired label={t('Name')} data-testid="name-group">
187	          <TextInput
188	            data-testid="name-input"
189	            aria-label="form name input"
190	            value={name}
191	            onChange={(_, value) => handleChangeName(value)}
192	            isDisabled={!!siteName}
193	          />
194	        </FormGroup>
195	      )}
196	
197	      {show.linkAccess && (
198	        <FormGroup
199	          label={t('Link access')}
200	          labelIcon={<TooltipInfoButton content={t('tooltipSiteLinkAccess')} />}
201	          fieldId="form-linkAccess"
202	          data-testid="link-access-group"
203	        >
204	          <Panel variant="bordered">
205	            <PanelMain>
206	              <PanelMainBody>
207	                <Checkbox
208	                  data-testid="link-access-checkbox"
209	                  id="enable-link-access"
210	                  label={t('Enable link access')}
211	                  onChange={() => setToggleLinkAccess(!isLinkAccessExist)}
212	                  isChecked={isLinkAccessExist}
213	                  className="pf-v5-u-mb-md"
214	                />
215	
216	                <FormSelect
217	                  data-testid="link-access-select"
218	                  aria-label="form link access select"
219	                  value={linkAccess}
220	                  onChange={(_, value) => handleChangeLinkAccess(value)}
221	                  isDisabled={!isLinkAccessExist}
222	                >
