227	                      key={index}
228	                      value={option.value}
229	                      label={option.label}
230	                    />
231	                  ))}
232	                </FormSelect>
233	              </PanelMainBody>
234	            </PanelMain>
235	          </Panel>
236	        </FormGroup>
237	      )}
238	
239	      {!(show.serviceAccount && show.ha) && (
240	        <SecondaryOptions
241	          showServiceAccount={show.serviceAccount ?? false}
242	          showHa={show.ha ?? false}
243	          showDefaultIssuer={show.defaultIssuer ?? false}
244	          serviceAccount={serviceAccount}
245	          defaultIssuer={defaultIssuer}
246	          ha={ha}
247	          onChangeServiceAccount={handleChangeServiceAccount}
248	          onDefaultIssuer={handleDefaultIssuer}
249	          onChangeHa={handleChangeHa}
250	        />
251	      )}
252	
253	      {show.serviceAccount && show.ha && (
254	        <ExpandableSection
255	          data-testid="expandable-section"
256	          toggleText={isExpanded ? 'Show less' : 'Show more'}
257	          onToggle={handleToggle}
258	          isExpanded={isExpanded}
259	        >
260	          <SecondaryOptions
261	            showServiceAccount={show.serviceAccount ?? false}
262	            showHa={show.ha ?? false}
263	            showDefaultIssuer={show.defaultIssuer ?? false}
264	            serviceAccount={serviceAccount}
265	            defaultIssuer={defaultIssuer}
266	            ha={ha}
267	            onChangeServiceAccount={handleChangeServiceAccount}
268	            onDefaultIssuer={handleDefaultIssuer}
269	            onChangeHa={handleChangeHa}
270	          />
271	        </ExpandableSection>
272	      )}
