258	          isExpanded={isExpanded}
259	        >
260	          <SecondaryOptions
261	            showServiceAccount={show.serviceAccount ?? false}
262	            showHa={show.ha ?? false}
263	            showDefaultIssuer={show.defaultIssuer ?? false}
264	            serviceAccount={serviceAccount}
265	            defaultIssuer={defaultIssuer}
266	            ha={ha}
267	            onChangeServiceAccount={handleChangeServiceAccount}
268	            onDefaultIssuer={handleDefaultIssuer}
269	            onChangeHa={handleChangeHa}
270	          />
271	        </ExpandableSection>
272	      )}
273	
274	      {validated && (
275	        <FormAlert>
276	          <Alert
277	            data-testid="validation-alert"
278	            variant="danger"
279	            title={t('An error occurred')}
280	            aria-live="polite"
281	            isInline
282	          >
283	            {validated}
284	          </Alert>
285	        </FormAlert>
286	      )}
287	
288	      <ActionGroup style={{ display: 'flex' }}>
289	        <Button data-testid="submit-button" variant="primary" onClick={handleSubmit} isDisabled={!canSubmit}>
290	          {t('Submit')}
291	        </Button>
292	
293	        <Button data-testid="cancel-button" variant="link" onClick={onCancel}>
294	          {t('Cancel')}
295	        </Button>
296	      </ActionGroup>
297	    </Form>
298	  );
299	};
300	const WaitSiteCreation = function () {
301	  const { t } = useTranslation(I18nNamespace);
302	
303	  return (
304	    <Card isPlain data-testid="loading-card">
305	      <CardBody>
306	        <PageSection variant={PageSectionVariants.light} padding={{ default: 'noPadding' }}>
