308	        </PageSection>
309	      </CardBody>
310	    </Card>
311	  );
312	};
313	
314	interface SecondaryOptionsProps {
315	  showServiceAccount: boolean;
316	  showHa: boolean;
317	  showDefaultIssuer: boolean;
318	  serviceAccount: string;
319	  defaultIssuer: string;
320	  ha: boolean;
321	  onChangeServiceAccount: (value: string) => void;
322	  onDefaultIssuer: (value: string) => void;
323	  onChangeHa: (value: boolean) => void;
